const body = $input.item.json.body || $input.item.json || {};
const chatInput = (body.chatInput || body.message || body.text || '').trim();
let metadata = body.metadata || {};
if (typeof metadata === 'string') {
  try { metadata = JSON.parse(metadata); } catch(e) { metadata = {}; }
}
const sessionKey = (
  metadata.sessionId || metadata.session_id ||
  body.sessionId || body.session_id ||
  `chat_${Date.now()}_${Math.random().toString(36).slice(2,7)}`
);
const files = body.files || [];
return {
  json: {
    chatInput,
    sessionKey,
    metadata,
    files,
    hasFiles: files.length > 0,
    utmSource:   metadata.utm_source   || body.utm_source   || null,
    utmMedium:   metadata.utm_medium   || body.utm_medium   || null,
    utmCampaign: metadata.utm_campaign || body.utm_campaign || null,
    sourceUrl:   metadata.source_url   || body.source_url   || null,
    timestamp: new Date().toISOString()
  }
};

const query = $input.item.json.query || $input.item.json.input || '{}';
let data;
try { data = typeof query === 'string' ? JSON.parse(query) : query; } catch(e) { data = {}; }

const sessionKey = data.session_key || $('Normalize Input').item.json.sessionKey;
if (!sessionKey) return { error: 'session_key is required' };

const body = {
  p_session_key: sessionKey,
  p_business_name: data.businessName || data.business_name || null,
  p_niche: 'HVAC',
  p_stage: data.stage || 'New',
  p_lead_type: 'inbound_chat',
  p_issue_type: data.issue_type || null,
  p_equipment_type: data.equipment_type || null,
  p_urgency: data.urgency || null,
  p_system_down: data.system_down || false,
  p_name: data.name || null,
  p_phone: data.phone || null,
  p_email: data.email || null,
  p_service_address: data.service_address || null,
  p_zip: data.zip || null,
  p_preferred_time_window: data.preferred_time_window || null,
  p_priority: data.priority || null,
  p_consent_to_contact: data.consent_to_contact || false,
  p_chat_summary: data.chat_summary || null,
  p_place_id: data.placeId || null
};

const supabaseUrl = $env.SUPABASE_URL;
const supabaseKey = $env.SUPABASE_SERVICE_KEY;

const resp = await fetch(supabaseUrl + '/rest/v1/rpc/upsert_lead', {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'apikey': supabaseKey,
    'Authorization': 'Bearer ' + supabaseKey,
    'Prefer': 'return=representation'
  },
  body: JSON.stringify(body)
});

const result = await resp.json();
if (!resp.ok) throw new Error('Upsert failed: ' + JSON.stringify(result));
return { success: true, lead: result };

const now = new Date();
const day = now.getDay(), hour = now.getHours();
let open = false, next = 'Monday at 8:00 AM';
if (day >= 1 && day <= 5) {
  open = hour >= 8 && hour < 18;
  next = open ? 'Now' : (hour < 8 ? 'Today at 8:00 AM' : 'Tomorrow at 8:00 AM');
} else if (day === 6) {
  open = hour >= 9 && hour < 14;
  next = open ? 'Now' : 'Monday at 8:00 AM';
}
return {
  is_business_hours: open,
  current_time: now.toISOString(),
  day_of_week: ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'][day],
  next_available: next,
  message: open ? 'Within business hours.' : `After hours. Next available: ${next}. Emergency line available 24/7.`
};
